func TestStructSizes(t *testing.T) {
	if got := unsafe.Sizeof(COREWEBVIEW2_COLOR{}); got != 4 {
		t.Errorf("sizeof(COREWEBVIEW2_COLOR) = %d, want 4", got)
	}
	if got := unsafe.Sizeof(COREWEBVIEW2_PHYSICAL_KEY_STATUS{}); got != 24 {
		t.Errorf("sizeof(COREWEBVIEW2_PHYSICAL_KEY_STATUS) = %d, want 24", got)
	}
	if got := unsafe.Sizeof(EventRegistrationToken{}); got != 8 {
		t.Errorf("sizeof(EventRegistrationToken) = %d, want 8", got)
	}
	if got := unsafe.Sizeof(POINT{}); got != 8 {
		t.Errorf("sizeof(POINT) = %d, want 8", got)
	}
	if got := unsafe.Sizeof(RECT{}); got != 16 {
		t.Errorf("sizeof(RECT) = %d, want 16", got)
	}
	// VARIANT is 24 bytes on win64 (BRECORD arm is two pointers), 16 on win32.
	if got, want := unsafe.Sizeof(VARIANT{}), 8+2*unsafe.Sizeof(uintptr(0)); got != want {
		t.Errorf("sizeof(VARIANT) = %d, want %d", got, want)
	}
}

